// // This DFF module has a clock input (clk), a reset input (rst), a data input (D), and an output (Q). On the falling edge of the clock, if reset is low, the output Q should be set to 1. Otherwise, the output Q should take the value of D.
module DFF (
    input clk,
    input rst,
    input D,
    output reg Q
);
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            Q <= 0;
        end else begin
            Q <= D;
        end
    end
endmodule
